INSERT INTO public.exercises (external_id,name,muscle_group,secondary_muscles,equipment,category,instructions,description,image_url,source,is_public) VALUES ('Standing_Front_Barbell_Raise_Over_Head','Standing Front Barbell Raise Over Head','hombros',ARRAY[]::text[],'barra','strength',ARRAY['To begin, stand straight with a barbell in your hands. You should grip the bar with palms facing down and a closer than shoulder width grip apart from each other.','Your feet should be shoulder width apart from each other. Your elbows should be slightly bent. This is the starting position.','Lift the barbell up until it is directly over your head while exhaling. Make sure to keep your elbows slightly bent when performing each repetition.','Once you feel the contraction, begin to lower the barbell back down to the starting position as you inhale.','Repeat for the recommended amount of repetitions.'],'To begin, stand straight with a barbell in your hands. You should grip the bar with palms facing down and a closer than shoulder width grip apart from each other. Your feet should be shoulder width apart from each other. Your elbows should be slightly bent. This is the starting position. Lift the barbell up until it is directly over your head while exhaling. Make sure to keep your elbows slightly bent when performing each repetition. Once you feel the contraction, begin to lower the barbell back down to the starting position as you inhale. Repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Front_Barbell_Raise_Over_Head/0.jpg','exercisedb',true),('Standing_Gastrocnemius_Calf_Stretch','Standing Gastrocnemius Calf Stretch','pantorrillas',ARRAY['isquiotibiales'],NULL,'stretching',ARRAY['Place your right heel on a step with your knee extended and lean forward to grab your right toe with your right hand. Your left knee should be slightly bent and your back should be straight.','Support your weight on your left leg and place your left hand on your left thigh.','Pull your right toes toward your knee until you feel a stretch in your calf.'],'Place your right heel on a step with your knee extended and lean forward to grab your right toe with your right hand. Your left knee should be slightly bent and your back should be straight. Support your weight on your left leg and place your left hand on your left thigh. Pull your right toes toward your knee until you feel a stretch in your calf.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Gastrocnemius_Calf_Stretch/0.jpg','exercisedb',true),('Standing_Hamstring_and_Calf_Stretch','Standing Hamstring and Calf Stretch','isquiotibiales',ARRAY[]::text[],'otro','stretching',ARRAY['Being by looping a belt, band, or rope around one foot. While standing, place that foot forward.','Bend your back leg, while keeping the front one straight. Now raise the toes of your front foot off of the ground and lean forward.','Using the belt, pull on the top of the foot to increase the stretch in the calf. Hold for 10-20 seconds and repeat with the other foot.'],'Being by looping a belt, band, or rope around one foot. While standing, place that foot forward. Bend your back leg, while keeping the front one straight. Now raise the toes of your front foot off of the ground and lean forward. Using the belt, pull on the top of the foot to increase the stretch in the calf. Hold for 10-20 seconds and repeat with the other foot.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Hamstring_and_Calf_Stretch/0.jpg','exercisedb',true),('Standing_Hip_Circles','Standing Hip Circles','abductores',ARRAY['aductores'],'peso corporal','stretching',ARRAY['Begin standing on one leg, holding to a vertical support.','Raise the unsupported knee to 90 degrees. This will be your starting position.','Open the hip as far as possible, attempting to make a big circle with your knee.','Perform this movement slowly for a number of repetitions, and repeat on the other side.'],'Begin standing on one leg, holding to a vertical support. Raise the unsupported knee to 90 degrees. This will be your starting position. Open the hip as far as possible, attempting to make a big circle with your knee. Perform this movement slowly for a number of repetitions, and repeat on the other side.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Hip_Circles/0.jpg','exercisedb',true),('Standing_Hip_Flexors','Standing Hip Flexors','cuádriceps',ARRAY[]::text[],NULL,'stretching',ARRAY['Stand up straight with the spine vertical, the left foot slightly in front of the right.','Bend both knees and lift the back heel off the floor as you press the right hip forward. You can''''t get a thorough, deep stretch in this position, however, because it''''s hard to relax the hip flexor and stand on it at the same time. Switch sides.'],'Stand up straight with the spine vertical, the left foot slightly in front of the right. Bend both knees and lift the back heel off the floor as you press the right hip forward. You can''t get a thorough, deep stretch in this position, however, because it''s hard to relax the hip flexor and stand on it at the same time. Switch sides.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Hip_Flexors/0.jpg','exercisedb',true),('Standing_Inner-Biceps_Curl','Standing Inner-Biceps Curl','bíceps',ARRAY[]::text[],'mancuernas','strength',ARRAY['Stand up with a dumbbell in each hand being held at arms length. The elbows should be close to the torso. Your legs should be at about shoulder''''s width apart from each other.','Rotate the palms of the hands so that they are facing inward in a neutral position. This will be your starting position.','While holding the upper arms stationary, curl the weights out while contracting the biceps as you breathe out. Your wrist should turn so that when the weights are fully elevated you have supinated grip (palms facing up).','Only the forearms should move. Continue the movement until your biceps are fully contracted and the dumbbells are at shoulder level. Tip: Keep the forearms aligned with your outer deltoids.','Hold the contracted position for a second as you squeeze the biceps.','Slowly begin to bring the dumbbells back to the starting position as your breathe in. Remember to rotate the wrists as you lower the weight in order to switch back to a neutral grip.','Repeat for the recommended amount of repetitions.'],'Stand up with a dumbbell in each hand being held at arms length. The elbows should be close to the torso. Your legs should be at about shoulder''s width apart from each other. Rotate the palms of the hands so that they are facing inward in a neutral position. This will be your starting position. While holding the upper arms stationary, curl the weights out while contracting the biceps as you breathe out. Your wrist should turn so that when the weights are fully elevated you have supinated grip (palms facing up). Only the forearms should move. Continue the movement until your biceps are fully contracted and the dumbbells are at shoulder level. Tip: Keep the forearms aligned with your outer deltoids. Hold the contracted position for a second as you squeeze the biceps. Slowly begin to bring the dumbbells back to the starting position as your breathe in. Remember to rotate the wrists as you lower the weight in order to switch back to a neutral grip. Repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Inner-Biceps_Curl/0.jpg','exercisedb',true),('Standing_Lateral_Stretch','Standing Lateral Stretch','abdominales',ARRAY[]::text[],NULL,'stretching',ARRAY['Take a slightly wider than hip distance stance with your knees slightly bent.','Place your right hand on your right hip to support the spine.','Raise your left arm in a vertical line and place your left hand behind your head. Keep it there as you incline your torso to the right.','Keep your weight evenly distributed between both legs (don''''t lean into your left hip). Switch sides.'],'Take a slightly wider than hip distance stance with your knees slightly bent. Place your right hand on your right hip to support the spine. Raise your left arm in a vertical line and place your left hand behind your head. Keep it there as you incline your torso to the right. Keep your weight evenly distributed between both legs (don''t lean into your left hip). Switch sides.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Lateral_Stretch/0.jpg','exercisedb',true),('Standing_Leg_Curl','Standing Leg Curl','isquiotibiales',ARRAY[]::text[],'máquina','strength',ARRAY['Adjust the machine lever to fit your height and lie with your torso bent at the waist facing forward around 30-45 degrees (since an angled position is more favorable for hamstrings recruitment) with the pad of the lever on the back of your right leg (just a few inches under the calves) and the front of the right leg on top of the machine pad.','Keeping the torso bent forward, ensure your leg is fully stretched and grab the side handles of the machine. Position your toes straight. This will be your starting position.','As you exhale, curl your right leg up as far as possible without lifting the upper leg from the pad. Once you hit the fully contracted position, hold it for a second.','As you inhale, bring the legs back to the initial position. Repeat for the recommended amount of repetitions.','Perform the same exercise now for the left leg.'],'Adjust the machine lever to fit your height and lie with your torso bent at the waist facing forward around 30-45 degrees (since an angled position is more favorable for hamstrings recruitment) with the pad of the lever on the back of your right leg (just a few inches under the calves) and the front of the right leg on top of the machine pad. Keeping the torso bent forward, ensure your leg is fully stretched and grab the side handles of the machine. Position your toes straight. This will be your starting position. As you exhale, curl your right leg up as far as possible without lifting the upper leg from the pad. Once you hit the fully contracted position, hold it for a second. As you inhale, bring the legs back to the initial position. Repeat for the recommended amount of repetitions. Perform the same exercise now for the left leg.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Leg_Curl/0.jpg','exercisedb',true),('Standing_Long_Jump','Standing Long Jump','cuádriceps',ARRAY['pantorrillas','glúteos','isquiotibiales'],'peso corporal','plyometrics',ARRAY['This drill is best done in sand or other soft landing surface. Ensure that you are able to measure distance. Stand in a partial squat stance with feet shoulder width apart.','Utilizing a big arm swing and a countermovement of the legs, jump forward as far as you can.','Attempt to land with your feet out in front you, reaching as far as possible with your legs.','Measure the distance from your landing point to the starting point and track results.'],'This drill is best done in sand or other soft landing surface. Ensure that you are able to measure distance. Stand in a partial squat stance with feet shoulder width apart. Utilizing a big arm swing and a countermovement of the legs, jump forward as far as you can. Attempt to land with your feet out in front you, reaching as far as possible with your legs. Measure the distance from your landing point to the starting point and track results.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Long_Jump/0.jpg','exercisedb',true),('Standing_Low-Pulley_Deltoid_Raise','Standing Low-Pulley Deltoid Raise','hombros',ARRAY['antebrazos'],'cable','strength',ARRAY['Start by standing to the right side of a low pulley row. Use your left hand to come across the body and grab a single handle attached to the low pulley with a pronated grip (palms facing down). Rest your arm in front of you. Your right hand should grab the machine for better support and balance.','Make sure that your back is erect and your feet are shoulder width apart from each other. This is the starting position.','Begin to use the left hand and come across your body out until it is elevated to shoulder height while exhaling.','Feel the contraction at the top for a second and begin to slowly lower the handle back down to the original starting position while inhaling.','Repeat for the recommended amount of repetitions.','Switch arms and repeat the exercise.'],'Start by standing to the right side of a low pulley row. Use your left hand to come across the body and grab a single handle attached to the low pulley with a pronated grip (palms facing down). Rest your arm in front of you. Your right hand should grab the machine for better support and balance. Make sure that your back is erect and your feet are shoulder width apart from each other. This is the starting position. Begin to use the left hand and come across your body out until it is elevated to shoulder height while exhaling. Feel the contraction at the top for a second and begin to slowly lower the handle back down to the original starting position while inhaling. Repeat for the recommended amount of repetitions. Switch arms and repeat the exercise.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Standing_Low-Pulley_Deltoid_Raise/0.jpg','exercisedb',true);